mcqs.question:
What is printed by the following code?

#include <iostream>
using namespace std;
class Test {
 int x;
public:
 Test(int val) : x(val) {}
 void display() { cout << x; }
};
void func(Test t) {
 t.display();
}
int main() {
 Test obj(10);
 func(obj);
 return 0;
}

What will be the output?

class Sample {
 int id;
public:
 Sample(int i) { id = i; }
 void modify(Sample s) { s.id = 100; }
 int getId() { return id; }
};
int main() {
 Sample obj(10);
 obj.modify(obj);
 cout << obj.getId();
}

What happens if you return a reference to a local variable?

int& func() {
 int x = 5;
 return x;
}

What is the output?

class A {
public:
 int x;
 A(int val) : x(val) {}
};
void change(A* ptr) {
 ptr->x = 50;
}
int main() {
 A obj(10);
 change(&obj);
 cout << obj.x;
 return 0;
}
